// WF14 — Build Payment Batch
// Reads all unbatched approved invoices and creates a payment batch

const invoices = $input.all();
const now = new Date();

// Generate batch ID: BATCH-YYYY-WNN
const year = now.getFullYear();
const startOfYear = new Date(year, 0, 1);
const dayOfYear = Math.floor((now - startOfYear) / 86400000);
const weekNum = Math.ceil((dayOfYear + startOfYear.getDay() + 1) / 7);
const batchId = `BATCH-${year}-W${String(weekNum).padStart(2, '0')}`;

// Due date cutoff: 7 days from now
const cutoffDate = new Date(now);
cutoffDate.setDate(cutoffDate.getDate() + 7);
const cutoffStr = cutoffDate.toISOString().split('T')[0];
const batchDateStr = now.toISOString().split('T')[0];

// Build invoice records
const invoicesJson = [];
const vendorSummary = {};
let totalAmount = 0;
let earlyDiscountTotal = 0;
const recordIds = []; // Airtable record IDs for batch update

for (const inv of invoices) {
  const f = inv.json.fields || inv.json;
  const amount = parseFloat(f.invoice_amount || f.total_amount) || 0;
  totalAmount += amount;

  const record = {
    invoice_id: f.invoice_id || f.invoice_number || 'N/A',
    vendor_invoice_number: f.invoice_number || 'N/A',
    vendor_name: f.seller_name || f.vendor_name || 'Unknown',
    po_number: f.po_number || '',
    amount: amount,
    due_date: f.due_date || f.invoice_date || '',
    gl_account: f.gl_account || '',
    match_status: f.match_status?.name || f.match_status || 'Unknown'
  };

  invoicesJson.push(record);
  recordIds.push(inv.json.id);

  // Group by vendor
  const vendorName = record.vendor_name;
  if (!vendorSummary[vendorName]) {
    vendorSummary[vendorName] = { invoices: [], total: 0 };
  }
  vendorSummary[vendorName].invoices.push(record);
  vendorSummary[vendorName].total += amount;

  // Check early payment discount
  if (f.early_discount_eligible && f.early_discount_deadline) {
    const deadline = new Date(f.early_discount_deadline);
    if (deadline >= now) {
      earlyDiscountTotal += parseFloat(f.early_discount_amount) || 0;
    }
  }
}

// Format EUR helper
const fmtEur = (n) => `€${n.toLocaleString('de-DE', {minimumFractionDigits: 2, maximumFractionDigits: 2})}`;

// Build Slack message
let slackMsg = `💳 *BATCH ZA PLAĆANJE — ${batchId}*\n`;
slackMsg += `Datum kreiranja: ${now.toLocaleDateString('de-DE')}\n`;
slackMsg += `Rok za plaćanje: do ${cutoffDate.toLocaleDateString('de-DE')}\n\n`;
slackMsg += `📋 *PREGLED PO DOBAVLJAČIMA:*\n━━━━━━━━━━━━━━━━━━━━━━━━\n`;

for (const [vendor, data] of Object.entries(vendorSummary)) {
  slackMsg += `🏢 *${vendor}*\n`;
  for (const inv of data.invoices) {
    const dueShort = inv.due_date ? new Date(inv.due_date).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' }) : 'N/A';
    slackMsg += `   • ${inv.vendor_invoice_number} (${inv.po_number || 'bez PO'}) — ${fmtEur(inv.amount)} — rok: ${dueShort}\n`;
  }
  slackMsg += `   Ukupno ${vendor}: ${fmtEur(data.total)}\n\n`;
}

slackMsg += `━━━━━━━━━━━━━━━━━━━━━━━━\n`;
slackMsg += `*UKUPNO ZA PLAĆANJE: ${fmtEur(totalAmount)}*\n`;
slackMsg += `Broj faktura: ${invoices.length} | Broj dobavljača: ${Object.keys(vendorSummary).length}`;

if (earlyDiscountTotal > 0) {
  slackMsg += `\n\n💡 _Moguća ušteda za rano plaćanje: ${fmtEur(earlyDiscountTotal)}_`;
}

// Build payment instruction email HTML
let emailHtml = `<div style="font-family: Arial, sans-serif; max-width: 700px;">`;
emailHtml += `<div style="background: #1a1a2e; color: white; padding: 20px;"><h2 style="margin:0;">Hotel Jadran — Nalog za plaćanje</h2>`;
emailHtml += `<p style="margin:5px 0 0;">Batch: ${batchId} | Datum: ${now.toLocaleDateString('de-DE')}</p></div>`;
emailHtml += `<table style="width:100%; border-collapse:collapse; margin-top:20px;"><thead><tr style="background:#f0f0f0;">`;
emailHtml += `<th style="padding:10px; text-align:left;">Dobavljač</th>`;
emailHtml += `<th style="padding:10px; text-align:left;">Br. fakture</th>`;
emailHtml += `<th style="padding:10px; text-align:left;">PO</th>`;
emailHtml += `<th style="padding:10px; text-align:right;">Iznos (EUR)</th>`;
emailHtml += `</tr></thead><tbody>`;

for (const inv of invoicesJson) {
  emailHtml += `<tr><td style="padding:8px; border-bottom:1px solid #eee;">${inv.vendor_name}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee;">${inv.vendor_invoice_number}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee;">${inv.po_number || '-'}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee; text-align:right;">${fmtEur(inv.amount)}</td></tr>`;
}

emailHtml += `</tbody><tfoot><tr style="background:#1a1a2e; color:white; font-weight:bold;">`;
emailHtml += `<td colspan="3" style="padding:10px;">UKUPNO ZA PLAĆANJE</td>`;
emailHtml += `<td style="padding:10px; text-align:right;">${fmtEur(totalAmount)}</td>`;
emailHtml += `</tr></tfoot></table>`;
emailHtml += `<p style="margin-top:20px; color:#666; font-size:12px;">Ovaj nalog je automatski generisan. Batch ID: ${batchId}</p></div>`;

return [{
  json: {
    batchId,
    batchDate: batchDateStr,
    dueDateCutoff: cutoffStr,
    totalAmount,
    invoiceCount: invoices.length,
    invoicesJson: JSON.stringify(invoicesJson),
    slackMessage: slackMsg,
    emailHtml,
    earlyDiscountTotal,
    recordIds,
    vendorCount: Object.keys(vendorSummary).length
  }
}];

// Update all invoice records: set payment_status = 'Batched' and payment_batch_id
const batchData = $('Code - Build Payment Batch').first().json;
const batchId = batchData.batchId;
const recordIds = batchData.recordIds;

// Output one item per invoice record to update
const updates = recordIds.map(id => ({
  json: {
    recordId: id,
    batchId: batchId
  }
}));

return updates;

// Parse Slack interactive callback payload
const body = $input.first().json.body;

// Slack sends interactive payloads as application/x-www-form-urlencoded with a 'payload' field
let payload;
try {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body;
} catch (e) {
  payload = body;
}

const action = payload.actions?.[0]?.value || '';
const userName = payload.user?.name || payload.user?.username || 'Unknown';
const responseUrl = payload.response_url || '';

// Parse action: "approve_BATCH-2026-W14" or "reject_BATCH-2026-W14"
const parts = action.split('_');
const decision = parts[0]; // 'approve' or 'reject'
const batchId = action.replace(/^(approve|reject)_/, ''); // everything after first underscore group

return [{
  json: {
    decision,
    batchId,
    userName,
    responseUrl,
    timestamp: new Date().toISOString()
  }
}];

// Build payment instruction email and extract invoice record IDs for status update
const batchRecord = $('Airtable - Get Batch (Approve Path)').first().json;
const callbackData = $('Code - Parse Slack Callback').first().json;
const f = batchRecord.fields || batchRecord;

const batchId = f.batch_id;
const totalAmount = parseFloat(f.total_amount) || 0;
const invoicesJson = JSON.parse(f.invoices_json || '[]');

const fmtEur = (n) => `€${n.toLocaleString('de-DE', {minimumFractionDigits: 2, maximumFractionDigits: 2})}`;

// Build email HTML
let emailHtml = `<div style="font-family: Arial, sans-serif; max-width: 700px;">`;
emailHtml += `<div style="background: #1a1a2e; color: white; padding: 20px;"><h2 style="margin:0;">Hotel Jadran — Nalog za plaćanje</h2>`;
emailHtml += `<p style="margin:5px 0 0;">Batch: ${batchId} | Odobrio: ${callbackData.userName} | Datum: ${new Date().toLocaleDateString('de-DE')}</p></div>`;
emailHtml += `<table style="width:100%; border-collapse:collapse; margin-top:20px;"><thead><tr style="background:#f0f0f0;">`;
emailHtml += `<th style="padding:10px; text-align:left;">Dobavljač</th>`;
emailHtml += `<th style="padding:10px; text-align:left;">Br. fakture</th>`;
emailHtml += `<th style="padding:10px; text-align:left;">PO</th>`;
emailHtml += `<th style="padding:10px; text-align:right;">Iznos (EUR)</th>`;
emailHtml += `</tr></thead><tbody>`;

for (const inv of invoicesJson) {
  emailHtml += `<tr><td style="padding:8px; border-bottom:1px solid #eee;">${inv.vendor_name}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee;">${inv.vendor_invoice_number}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee;">${inv.po_number || '-'}</td>`;
  emailHtml += `<td style="padding:8px; border-bottom:1px solid #eee; text-align:right;">${fmtEur(inv.amount)}</td></tr>`;
}

emailHtml += `</tbody><tfoot><tr style="background:#1a1a2e; color:white; font-weight:bold;">`;
emailHtml += `<td colspan="3" style="padding:10px;">UKUPNO ZA PLAĆANJE</td>`;
emailHtml += `<td style="padding:10px; text-align:right;">${fmtEur(totalAmount)}</td>`;
emailHtml += `</tr></tfoot></table>`;
emailHtml += `<p style="margin-top:20px; color:#666; font-size:12px;">Ovaj nalog je automatski generisan. Batch ID: ${batchId}</p></div>`;

return [{
  json: {
    batchId,
    totalAmount,
    invoiceCount: invoicesJson.length,
    emailHtml,
    emailSubject: `Hotel Jadran — Nalog za plaćanje: ${batchId}`,
    approvedBy: callbackData.userName,
    responseUrl: callbackData.responseUrl
  }
}];

// Get invoices from the rejected batch and prepare to unbatch them
const batchRecord = $('Airtable - Get Batch (Reject Path)').first().json;
const f = batchRecord.fields || batchRecord;
const invoicesJson = JSON.parse(f.invoices_json || '[]');
const callbackData = $('Code - Parse Slack Callback').first().json;

// We need to find invoice records by invoice_number and clear their batch assignment
// Return info needed for downstream nodes
return [{
  json: {
    batchId: f.batch_id,
    totalAmount: parseFloat(f.total_amount) || 0,
    invoiceCount: invoicesJson.length,
    rejectedBy: callbackData.userName,
    responseUrl: callbackData.responseUrl
  }
}];
